parameters.functionCode:
const ticket = $input.first().json;

// Classify ticket type
let category = 'general';
let priority = 'normal';
let autoReply = '';

const message = ticket.message.toLowerCase();

if (message.includes('commande') || message.includes('order')) {
  category = 'order';
  priority = 'high';
  autoReply = 'Votre demande concernant votre commande a ete enregistree. Notre equipe va vous repondre sous 2h.';
} else if (message.includes('remboursement') || message.includes('retour')) {
  category = 'refund';
  priority = 'high';
  autoReply = 'Nous avons recu votre demande de remboursement. Le traitement prend 5-10 jours ouvres.';
} else if (message.includes('livraison') || message.includes('shipping')) {
  category = 'shipping';
  autoReply = 'Pour le suivi de votre livraison, rendez-vous sur notre page de suivi avec votre numero de commande.';
} else if (message.includes('produit') || message.includes('defectueux')) {
  category = 'product';
  autoReply = 'Nous sommes desoles pour ce probleme. Envoyez-nous des photos du produit et nous trouverons une solution.';
}

return [{json: {...ticket, category, priority, autoReply, agent: 'support'}}];

